// Browser-side: consume SSE via fetch + ReadableStream (works for POST requests)
async function streamCompletion(message, onChunk, onDone, onError) {
  let response;
  try {
    response = await fetch('/stream', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message }),
    });
  } catch (err) {
    onError(err); return;
  }

  if (!response.ok) { onError(new Error(`HTTP ${response.status}`)); return; }

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    buffer += decoder.decode(value, { stream: true });
    const blocks = buffer.split('\n\n');
    buffer = blocks.pop();            // keep the incomplete trailing segment

    for (const block of blocks) {
      if (!block.startsWith('data: ')) continue;
      const payload = JSON.parse(block.slice(6));
      if (payload.type === 'done')  { onDone(); return; }
      if (payload.type === 'delta') onChunk(payload.text);
    }
  }
}

// Usage
let fullText = '';
await streamCompletion(
  'Explain photosynthesis',
  (chunk) => {
    fullText += chunk;
    document.getElementById('output').textContent = fullText;
  },
  () => console.log('Complete'),
  (err) => console.error('Error', err),
);

